// ============================================================
//  NODE: Hash Data & Siapkan Payload Meta CAPI
//  Dokumentasi CAPI: https://developers.facebook.com/docs/marketing-api/conversions-api
// ============================================================

const crypto = require('crypto');

// Helper: SHA-256 hash untuk data PII sesuai syarat Meta
function sha256(value) {
  if (!value || value.toString().trim() === '') return null;
  return crypto
    .createHash('sha256')
    .update(value.toString().trim().toLowerCase())
    .digest('hex');
}

// Ambil data dari baris Google Sheets
const row = $input.item.json;

const phone     = (row.No_HP || '').toString().replace(/\D/g, ''); // hilangkan non-digit
const nama      = (row.Nama || '').toString().trim();
const eventId   = (row.Event_ID || '').toString();
const paket     = (row.Paket || '').toString();
const sourceUrl = (row.Source_URL || 'https://madus4e.com').toString();

// Konversi nilai transaksi ke number
const orderValue = parseFloat((row.Order_Value || '0').toString().replace(/[^0-9.]/g, '')) || 0;

// Timestamp bayar (gunakan sekarang jika kosong)
const bayarTime = row.Waktu_Bayar
  ? new Date(row.Waktu_Bayar).getTime() / 1000
  : Math.floor(Date.now() / 1000);

// Bangun user_data dengan hash
const userData = {
  country: ['62'],          // kode negara Indonesia
};

if (phone) {
  // Format standar Meta: 62 + nomor (tanpa leading 0)
  const formattedPhone = phone.startsWith('0')
    ? '62' + phone.substring(1)
    : phone.startsWith('62')
    ? phone
    : '62' + phone;
  userData.ph = [sha256(formattedPhone)];
}

if (nama) {
  // Pisah nama depan dan belakang
  const namaParts = nama.split(' ');
  userData.fn = [sha256(namaParts[0])];
  if (namaParts.length > 1) {
    userData.ln = [sha256(namaParts.slice(1).join(' '))];
  }
}

// Payload final ke Meta CAPI
const payload = {
  data: [
    {
      event_name: 'Purchase',
      event_time: Math.floor(bayarTime),
      event_id: eventId + '_purchase',   // ID unik untuk dedup CAPI vs Pixel
      event_source_url: sourceUrl,
      action_source: 'website',
      user_data: userData,
      custom_data: {
        currency: 'IDR',
        value: orderValue,
        content_name: paket,
        content_type: 'product',
        order_id: eventId
      }
    }
  ]
};

// Teruskan event_id asli untuk update Sheets nanti
return {
  json: {
    ...payload,
    _meta: {
      event_id: eventId,
      row_index: row._rowNumber || row.rowNumber || null
    }
  }
};
